class Solution:
    def countPrefixes(self, root: TrieNode, words: List[str]) -> int:
        def dfs(node, word):
            if not node or not word:
                return 0
            if word in node.children:
                return 1 + dfs(node.children[word], word[1:])
            return dfs(node.children.get(word[0]), word[1:])

        count = 0
        for word in words:
            count += dfs(root, word)
        return count

