class Solution {
public:
int countPrefixes(TrieNode* root, vector<string>& words) {
	int count = 0;
	for (auto word : words) {
		int n = word.size();
		count += dfs(root, word, 0);
	}
	return count;
}

int dfs(TrieNode* node, const string& word, int i) {
	if (!node || i == word.size()) {
		return 0;
	}
	if (node->children.find(word[i]) != node->children.end()) {
		return 1 + dfs(node->children[word[i]], word, i + 1);
	}
	return dfs(node->children[word[i]], word, i + 1);
}
};

// Definition of TrieNode
struct TrieNode {
    unordered_map<char, TrieNode*> children;
    bool isEndOfWord;
};
